// bucket holds the token count and the last refill timestamp for a key.
type bucket struct {
	tokens int
	last   time.Time
}

// tokenLimiter implements a thread‑safe token‑bucket limiter.
type tokenLimiter struct {
	cfg     Config
	clock   Clock
	mu      sync.Mutex
	buckets map[string]*bucket
}

// newLimiter returns a Limiter implementation.
