	if clock == nil {
		clock = realClock{}
	}
	// If Burst is 0, default to Rate as the effective burst size.
	if cfg.Burst <= 0 {
		cfg.Burst = cfg.Rate
	}
	return &tokenLimiter{
		cfg:     cfg,
		clock:   clock,
		buckets: make(map[string]*bucket),
	}
}

