	}
	// Tokens to add = elapsed * rate / window
	added := int(float64(elapsed) * float64(l.cfg.Rate) / float64(l.cfg.Window))
	if added > 0 {
		b.tokens += added
		if b.tokens > l.cfg.Burst {
			b.tokens = l.cfg.Burst
		}
		b.last = now
	}
}

// Allow checks whether a request for the given key can proceed.
